+fn should_treat_input_as_path(input: &str) -> bool {
+    let has_path_separator = input.contains('/') || input.contains('\\');
+    if has_path_separator {
+        return true;
+    }
+
+    if looks_like_inline_mermaid(input) {
+        return has_file_extension_hint(input);
+    }
+
+    true
+}
