+fn has_file_extension_hint(input: &str) -> bool {
+    if input.chars().any(|c| c.is_whitespace()) {
+        return false;
+    }
+    let ext = Path::new(input)
+        .extension()
+        .and_then(|value| value.to_str())
+        .map(|value| value.to_ascii_lowercase());
+    ext.is_some()
+}
